INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 24001, 321, 1, 1, "リリ", 125801, 0, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 24001, 322, 1, 2, "クリア", 126001, 0, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 24001, 323, 1, 3, "プレシア", 126101, 0, "んーと。\nこれ、あげる。\nはい", 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 24001, 324, 2, 4, "リリ", 125801, 0, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 24001, 325, 2, 5, "クリア", 126001, 0, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 24001, 326, 2, 6, "プレシア", 126101, 0, "お兄。\nきてくれて、うれしい", 1, 40011);
